const items = $input.all();
const dateStr = new Date().toLocaleDateString('zh-CN', {month: 'long', day: 'numeric'});

if (items.length === 0) {
  return [{json: { subject: "Tech Briefing", email_body: "暂无内容" }}];
}

let html = `
<style>
  :root {
    color-scheme: light dark;
    supported-color-schemes: light dark;
  }

  @media (prefers-color-scheme: dark) {
    .dm-bg { background-color: #121212 !important; }
    .dm-text-main { color: #e8eaed !important; }
    .dm-text-muted { color: #9aa0a6 !important; }
    .dm-border-bottom { border-bottom: 2px solid #5f6368 !important; }
    .dm-border-top { border-top: 1px solid #5f6368 !important; }

    .dm-link { color: #8ab4f8 !important; }
  }
</style>

<div class="dm-bg dm-text-main" style="font-family: 'Helvetica Neue', Helvetica, Arial, sans-serif; max-width: 600px; margin: 0 auto; color: #000000;">

  <div class="dm-border-bottom" style="padding-bottom: 16px; border-bottom: 2px solid #000000; margin-bottom: 24px;">
    <h1 class="dm-text-main" style="margin: 0; font-size: 24px; font-weight: 700; letter-spacing: -0.5px; color: #000000;">Tech Briefing</h1>
    <p class="dm-text-main" style="margin: 4px 0 0 0; color: #000000; font-size: 14px; font-weight: 620;">${dateStr}</p>
  </div>

  <div>
`;

for (const item of items) {
    const news = item.json;

    let sourceLabel = "";
    let valueLabel = "";

    if (news.source_type === 'HackerNews') {
        sourceLabel = "Hacker News";
        valueLabel = `${news.points || 0} Points`;
    } else {
        sourceLabel = "TechCrunch";
        const dateObj = new Date(news.created_at);
        valueLabel = dateObj.toLocaleTimeString('zh-CN', {
            timeZone: 'Asia/Shanghai', 
            hour: '2-digit', 
            minute:'2-digit', 
            hour12: false
        });
    }

    let rawSentiment = news.sentiment || 'Neutral';
    let sentimentText = rawSentiment.charAt(0).toUpperCase() + rawSentiment.slice(1).toLowerCase();

    let sentimentColor = "#444444"; 
    if (sentimentText === 'Positive') sentimentColor = "#0d652d";
    if (sentimentText === 'Negative') sentimentColor = "#a50e0e";

    html += `
    <div style="margin-bottom: 28px;">

        <div class="dm-text-muted" style="font-size: 12px; color: #444444; margin-bottom: 4px; font-weight: 650;">
            <span class="dm-text-main" style="color: #000000;">${sourceLabel}</span>
            <span style="margin: 0 6px; color: #999;"></span>
            <span>${valueLabel}</span>
            <span style="margin: 0 6px; color: #999;"></span>
            <span style="color: ${sentimentColor};">${sentimentText}</span>
        </div>

        <h3 style="margin: 0 0 6px 0; font-size: 18px; line-height: 1.4; font-weight: 650;">
            <a href="${news.discussion_link}" class="dm-link" style="text-decoration: none; color: #1a73e8;">
                ${news.title_cn}
            </a>
        </h3>

        <p class="dm-text-main" style="margin: 0; font-size: 14px; color: #202124; line-height: 1.6; font-weight: 650;">
            ${news.summary || "暂无摘要"}
        </p>

    </div>
    `;
}

const dashboardUrl = "https://dashboard.trainingcqy.com"; 

html += `
  </div>
  <div class="dm-border-top" style="padding-top: 30px; border-top: 1px solid #dfe1e5; text-align: center;">

    <a href="${dashboardUrl}" style="display: inline-block; background-color: #1a73e8; color: #ffffff; padding: 12px 24px; border-radius: 4px; text-decoration: none; font-size: 14px; font-weight: 700; margin-bottom: 20px;">
      View Dashboard
    </a>

    <p class="dm-text-muted" style="margin: 0; color: #70757a; font-size: 12px;">
      &copy; 2026 trainingcqy.
    </p>

  </div>
</div>
`;

return [{
    json: {
        email_body: html,
        subject: "Tech Briefing"
    }
}];
